            type: 'code',
            value:
              '#!/bin/bash\n\n# 确保脚本以 root 权限运行\nif [[ $EUID -ne 0 ]]; then\n    echo "请使用 root 用户或 sudo 运行此脚本"\n    exit 1\nfi\n\n# 安装所需的基本软件包\necho "正在安装必需的软件包..."\napt update\nDEBIAN_FRONTEND=noninteractive apt install -y \\\n    ca-certificates curl gnupg software-properties-common sudo cifs-utils\n\n# 检查系统发行版和版本信息\n. /etc/os-release\n\n# 定义 Docker 源的 URL 和密钥\nDOCKER_GPG_KEY_URL="https://download.docker.com/linux"\nDOCKER_GPG_DIR="/etc/apt/keyrings"\nDOCKER_GPG_FILE="${DOCKER_GPG_DIR}/docker.gpg"\n\n# 检查系统发行版并设置相应的 Docker 源\necho "检测系统发行版..."\ncase "$ID" in\n    debian)\n        DOCKER_REPO_URL="${DOCKER_GPG_KEY_URL}/debian"\n        ;;\n    ubuntu)\n        DOCKER_REPO_URL="${DOCKER_GPG_KEY_URL}/ubuntu"\n        ;;\n    *)\n        echo "不支持的系统发行版: $ID"\n        exit 1\n        ;;\nesac\n\n# 创建目录并配置 Docker GPG 密钥\necho "正在配置 Docker GPG 密钥..."\nmkdir -p "$DOCKER_GPG_DIR"\ncurl -fsSL "${DOCKER_REPO_URL}/gpg" | gpg --dearmor -o "$DOCKER_GPG_FILE"\nchmod a+r "$DOCKER_GPG_FILE"\n\n# 添加 Docker 源到 sources.list\necho "正在添加 Docker 源..."\necho "deb [arch=amd64 signed-by=${DOCKER_GPG_FILE}] ${DOCKER_REPO_URL} ${VERSION_CODENAME} stable" | tee /etc/apt/sources.list.d/docker.list\n\n# 更新软件包列表\necho "正在更新软件包列表..."\napt update\n\n# 安装 Docker 及相关插件\necho "正在安装 Docker 组件..."\nDEBIAN_FRONTEND=noninteractive apt install -y \\\n    docker-ce docker-ce-cli containerd.io docker-buildx-plugin docker-compose-plugin\n\n# 启用并启动 Docker 服务\necho "正在重新加载 systemctl 并启动 Docker..."\nsystemctl daemon-reexec\nsystemctl enable --now docker\n\n# 验证 Docker 是否安装成功\necho "验证 Docker 安装..."\nif ! docker --version &>/dev/null; then\n    echo "Docker 安装失败，请检查错误日志！"\n    exit 1\nfi\n\necho "Docker 安装完成，当前版本：$(docker --version)"',
