              '<!DOCTYPE html>\n<html lang="zh">\n<head>\n    <meta charset="UTF-8">\n    <meta name="viewport" content="width=device-width, initial-scale=1.0">\n    <title>DHCP 租约监控</title>\n    <style>\n        body {\n            font-family: Arial, sans-serif;\n            text-align: center;\n        }\n        table {\n            width: 80%;\n            margin: auto;\n            border-collapse: collapse;\n        }\n        th, td {\n            border: 1px solid black;\n            padding: 8px;\n            text-align: center;\n        }\n        th {\n            background-color: #f2f2f2;\n        }\n    </style>\n    <script>\n        function fetchDhcpLeases() {\n            fetch("/api/dhcp-leases")\n                .then(response => response.json())\n                .then(data => {\n                    let tableBody = document.getElementById("lease-table-body");\n                    tableBody.innerHTML = "";\n\n                    data.forEach(lease => {\n                        let row = `<tr>\n                            <td>${lease.ip}</td>\n                            <td>${lease.mac}</td>\n                            <td>${lease.hostname}</td>\n                            <td>${lease.remaining_time} 秒</td>\n                        </tr>`;\n                        tableBody.innerHTML += row;\n                    });\n                })\n                .catch(error => console.error("获取 DHCP 租约失败:", error));\n        }\n\n        // 页面加载时获取数据\n        window.onload = function () {\n            fetchDhcpLeases();\n            setInterval(fetchDhcpLeases, 1000); // 每秒刷新\n        };\n    </script>\n</head>\n<body>\n    <h2>DHCP 租约监控</h2>\n    <table>\n        <thead>\n            <tr>\n                <th>IP 地址</th>\n                <th>MAC 地址</th>\n                <th>主机名</th>\n                <th>租约剩余时间</th>\n            </tr>\n        </thead>\n        <tbody id="lease-table-body">\n            <!-- 数据将在这里填充 -->\n        </tbody>\n    </table>\n</body>\n</html>',
