            type: 'code',
            value:
              'from flask import Flask, jsonify, render_template\nimport requests\nimport time\n\napp = Flask(__name__)\n\n# Kea DHCP Control Agent API 地址\nKEA_API_URL = "http://127.0.0.1:8000/"\n\ndef get_dhcp_leases():\n    """从 Kea API 获取 DHCP 租约信息，并格式化输出"""\n    try:\n        # 向 Kea API 发送 POST 请求\n        response = requests.post(KEA_API_URL, json={\n            "command": "lease4-get-all",\n            "service": ["dhcp4"]\n        }, timeout=5)\n\n        data = response.json()\n\n        # 检查返回的数据格式\n        if not isinstance(data, list) or len(data) == 0:\n            return {"error": "API 返回数据格式错误: 不是列表"}\n\n        data = data[0]  # 取列表中的第一个 JSON 对象\n\n        # 检查 API 响应是否正确\n        if "result" in data and data["result"] != 0:\n            return {"error": f"API 失败: {data.get(\'text\', \'未知错误\')}"}\n\n        if "arguments" not in data or "leases" not in data["arguments"]:\n            return {"error": "获取租约信息失败: API 返回数据格式错误"}\n\n        leases = data["arguments"]["leases"]\n\n        current_time = int(time.time())\n        leases_info = []\n\n        # 遍历每个租约\n        for lease in leases:\n            ip = lease.get("ip-address", "N/A")\n            mac = lease.get("hw-address", "N/A")\n            hostname = lease.get("hostname", "N/A")\n            expire = lease.get("cltt", 0) + lease.get("valid-lft", 0)  # 计算到期时间戳\n            remaining_time = max(expire - current_time, 0)\n\n            # 格式化剩余时间为 “X小时Y分钟Z秒”\n            hours = remaining_time // 3600\n            minutes = (remaining_time % 3600) // 60\n            seconds = remaining_time % 60\n            remaining_str = f"{hours}小时{minutes}分钟{seconds}秒"\n\n            leases_info.append({\n                "hostname": hostname,\n                "ip": ip,\n                "mac": mac,\n                "remaining": remaining_str\n            })\n\n        return {"leases": leases_info}\n\n    except requests.exceptions.RequestException as e:\n        return {"error": f"连接 Kea DHCP API 失败: {e}"}\n    except Exception as e:\n        return {"error": f"发生错误: {e}"}\n\n@app.route("/leases")\ndef leases():\n    """返回 DHCP 租约信息的 JSON 数据"""\n    result = get_dhcp_leases()\n    return jsonify(result)\n\n@app.route("/")\ndef index():\n    """返回前端页面"""\n    return render_template("index.html")\n\nif __name__ == "__main__":\n    # 启动 Flask 服务（生产环境请使用 WSGI 服务器）\n    app.run(host="0.0.0.0", port=5001, debug=True)',
            copyMode: 'block',
